render.css:
.kpi-segmented { display: flex; flex-direction: column; gap: 12px; }
.value-header { display: flex; align-items: baseline; justify-content: space-between; gap: 8px; }
.kpi-value { font-size: 28px; font-weight: 700; color: var(--ct-text-strong); letter-spacing: -0.02em; }
.badge-trend { font-size: 11px; font-weight: 600; color: var(--ct-accent-strong); padding: 3px 8px; background: var(--ct-accent-soft); border-radius: 10px; border: 1px solid var(--ct-border-accent); white-space: nowrap; }
.segmented-bar { display: flex; gap: 4px; height: 48px; }
.segment { flex: 1; background-color: var(--ct-text-strong); border-radius: 2px; }
.segment.inactive { background-color: var(--ct-surface-3); }
